const express = require('express');
const csrf = require('csurf');
const cookieParser = require('cookie-parser');
const session = require('express-session');

const app = express();

// Required middleware
app.use(cookieParser());
app.use(session({
  secret: process.env.SESSION_SECRET,
  resave: false,
  saveUninitialized: false,
  cookie: {
    httpOnly: true,
    secure: true, // HTTPS only
    sameSite: 'strict'
  }
}));
app.use(express.urlencoded({ extended: false }));

// CSRF protection middleware
const csrfProtection = csrf({ cookie: true });

// GET route: send CSRF token to client
app.get('/form', csrfProtection, (req, res) => {
  res.render('form', { csrfToken: req.csrfToken() });
});

// POST route: validate CSRF token
app.post('/transfer', csrfProtection, (req, res) => {
  // Token is automatically validated by middleware
  // If invalid, middleware returns 403 Forbidden

  const { amount, recipient } = req.body;
  // Process transfer...
  res.json({ success: true });
});

// Error handler for CSRF failures
app.use((err, req, res, next) => {
  if (err.code === 'EBADCSRFTOKEN') {
    res.status(403).json({ error: 'Invalid CSRF token' });
  } else {
    next(err);
  }
});

const session = require('express-session');

app.use(session({
  secret: process.env.SESSION_SECRET,
  resave: false,
  saveUninitialized: false,
  cookie: {
    httpOnly: true,      // Prevent JavaScript access
    secure: true,        // HTTPS only
    sameSite: 'strict',  // Prevent cross-site cookies
    maxAge: 3600000      // 1 hour
  }
}));

// SameSite values:
// - 'strict': Cookie NEVER sent on cross-site requests (most secure)
// - 'lax': Cookie sent on top-level navigation (GET only)
// - 'none': Cookie always sent (requires secure: true)

// For APIs that need cross-origin access, use 'lax'
app.use(session({
  secret: process.env.SESSION_SECRET,
  cookie: {
    sameSite: 'lax',
    secure: true
  }
}));

// CSRF protection via Origin/Referer validation
function validateOrigin(req, res, next) {
  const allowedOrigins = [
    'https://example.com',
    'https://www.example.com'
  ];

  // Check Origin header (modern browsers)
  const origin = req.get('Origin');
  if (origin) {
    if (!allowedOrigins.includes(origin)) {
      return res.status(403).json({ error: 'Forbidden: Invalid origin' });
    }
    return next();
  }

  // Fallback to Referer header (older browsers)
  const referer = req.get('Referer');
  if (referer) {
    const refererHost = new URL(referer).origin;
    if (!allowedOrigins.includes(refererHost)) {
      return res.status(403).json({ error: 'Forbidden: Invalid referer' });
    }
    return next();
  }

  // No Origin or Referer (suspicious)
  return res.status(403).json({ error: 'Forbidden: Missing origin headers' });
}

// Apply to state-changing routes
app.post('/transfer', validateOrigin, (req, res) => {
  // Process transfer...
  res.json({ success: true });
});

app.put('/user/profile', validateOrigin, (req, res) => {
  // Update profile...
  res.json({ success: true });
});

app.delete('/user/account', validateOrigin, (req, res) => {
  // Delete account...
  res.json({ success: true });
});
